const originalText = new WeakMap();
const originalAttributes = new WeakMap();

Object.assign(translations, {
  "AGB": "Terms",
  "Widerruf": "Withdrawal",
  "Widerrufsformular": "Withdrawal form",
  "Haftungsausschluss": "Disclaimer",
  "Cookies": "Cookies",
  "Abo kündigen": "Cancel subscription",
  "Rechtliche Hinweise zum Abonnement": "Legal subscription information",
  "Mit Klick auf den finalen Bestellbutton schließen Sie ein monatlich kündbares PointerScore-Abonnement zum Preis von 7,99 € pro Monat ab.": "By clicking the final order button, you enter into a monthly cancellable PointerScore subscription for €7.99 per month."
});

function translatedValue(original, language) {
  return language === "en" ? (translations[original] ?? original) : original;
}

window.PointerScoreI18n = {
  translate(value, language = document.documentElement.lang) { return translatedValue(String(value ?? ""), language); },
  get language() { return document.documentElement.lang === "en" ? "en" : "de"; },
  setLanguage: applyLanguage
};

function applyLanguage(language) {
  const walker = document.createTreeWalker(document.body, NodeFilter.SHOW_TEXT);
  const nodes = [];
  while (walker.nextNode()) nodes.push(walker.currentNode);
  nodes.forEach((node) => {
    const current = node.nodeValue ?? "";
    if (!current.trim()) return;
    if (!originalText.has(node)) originalText.set(node, current);
    const original = originalText.get(node) ?? current;
    const trimmed = original.trim();
    const translated = translatedValue(trimmed, language);
    node.nodeValue = original.replace(trimmed, translated);
  });

  document.querySelectorAll("[placeholder], [aria-label], [title], [data-tooltip]").forEach((element) => {
    ["placeholder", "aria-label", "title", "data-tooltip"].forEach((attribute) => {
      if (!element.hasAttribute(attribute)) return;
      let values = originalAttributes.get(element);
      if (!values) { values = {}; originalAttributes.set(element, values); }
      if (!(attribute in values)) values[attribute] = element.getAttribute(attribute) ?? "";
      element.setAttribute(attribute, translatedValue(values[attribute], language));
    });
  });

  document.documentElement.lang = language;
  document.title = translatedValue(originalDocumentTitle, language);

  const handbookHref = language === "de"
    ? "assets/PointerScore-Handbook.pdf"
    : "assets/PointerScore-Handbook-EN.pdf";
  document.querySelectorAll('a[href="assets/PointerScore-Handbook.pdf"], a[href="assets/PointerScore-Handbook-EN.pdf"]').forEach((link) => {
    link.setAttribute("href", handbookHref);
    link.setAttribute("download", language === "de" ? "PointerScore-Handbook-DE.pdf" : "PointerScore-Handbook-EN.pdf");
  });
  document.querySelectorAll("[data-language]").forEach((button) => {
    const active = button.getAttribute("data-language") === language;
    button.classList.toggle("is-active", active);
    button.setAttribute("aria-pressed", String(active));
  });
  localStorage.setItem("pointerscore-language", language);
  window.dispatchEvent(new CustomEvent("pointerscore:languagechange", { detail: { language } }));
}

function createLanguageSwitch() {
  const nav = document.querySelector(".nav");
  if (!nav || nav.querySelector(".language-switch")) return;
  const control = document.createElement("div");
  control.className = "language-switch";
  control.setAttribute("role", "group");
  control.setAttribute("aria-label", "Sprache auswählen");
  control.innerHTML = '<button type="button" data-language="de" aria-label="Deutsch">DE</button><button type="button" data-language="en" aria-label="English">EN</button>';
  const toggle = nav.querySelector(".nav-toggle");
  const menu = nav.querySelector(".nav-menu");
  nav.insertBefore(control, toggle || menu);
}

document.addEventListener("DOMContentLoaded", () => {
  createLanguageSwitch();
  document.querySelectorAll("[data-language]").forEach((button) => {
    if (button.dataset.languageBound === "true") return;
    button.dataset.languageBound = "true";
    button.addEventListener("click", () => applyLanguage(button.dataset.language));
  });
  const saved = localStorage.getItem("pointerscore-language");
  const detected = navigator.language.toLowerCase().startsWith("de") ? "de" : "en";
  applyLanguage(saved === "de" || saved === "en" ? saved : detected);
});
